/* Design system */

:root {
  --color-bg-primary: #050505;
  --color-bg-elevated: #0b0b0b;
  --color-bg-surface: #111111;

  --color-text-main: #ffffff;
  --color-text-soft: #f0f0f0;
  --color-text-muted: #a0a0a0;
  --color-text-subtle: #777777;
  --color-text-hero: #e0e0e0;

  --color-border-subtle: #262626;
  --color-border-strong: #333333;

  --color-accent: #e6ff2a;

  --color-success: #3dff7a;
  --color-error: #ff3355;
  --color-warning: #ffc94a;
  --color-info: #3da9ff;

  --font-heading: 'Space Grotesk', Helvetica, sans-serif;
  --font-body: 'Work Sans', Arial, sans-serif;
  --font-code: 'Source Code Pro', Menlo, Monaco, Consolas, 'Courier New', monospace;

  --font-size-xs: 11px;
  --font-size-sm: 13px;
  --font-size-base: 16px;
  --font-size-nav: 12px;
  --font-size-h1: 64px;
  --font-size-h2: 36px;
  --font-size-h3: 24px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  --radius-sm: 8px;
  --radius-md: 16px;
  --radius-lg: 24px;
  --radius-pill: 9999px;

  --transition-fast: 150ms ease-out;
  --transition-medium: 220ms ease-out;

  --max-width-shell: 1200px;
}

/* Global reset / base */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  height: 100%;
}

body {
  margin: 0;
  background-color: var(--color-bg-primary);
  color: var(--color-text-main);
  font-family: var(--font-body);
  font-size: var(--font-size-base);
  line-height: var(--line-height-normal);
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:focus-visible {
  outline: 2px solid var(--color-accent);
  outline-offset: 3px;
}

.shell {
  max-width: var(--max-width-shell);
  margin: 0 auto;
  padding-inline: var(--space-4);
}

/* Header */

.site-header {
  padding-top: var(--space-4);
  padding-bottom: var(--space-5);
  background-color: var(--color-bg-primary);
}

.nav-pill {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
  padding: 16px 32px;
  border-radius: var(--radius-pill);
  border: 1px solid var(--color-border-strong);
  background: radial-gradient(circle at top left, #111111 0, #050505 55%, #050505 100%);
}

.logo {
  display: inline-flex;
  align-items: center;
}

.logo-text {
  font-family: var(--font-heading);
  font-weight: 500;
  font-size: 22px;
  letter-spacing: 0.18em;
  text-transform: none;
  color: var(--color-text-main);
  white-space: nowrap;
}

.primary-nav {
  flex: 1;
}

.nav-list {
  display: flex;
  justify-content: flex-end;
  align-items: center;
  flex-wrap: wrap;
  gap: 18px;
  margin: 0;
  padding: 0;
  list-style: none;
}

.nav-link {
  position: relative;
  display: inline-block;
  padding-block: 2px;
  font-family: var(--font-body);
  font-size: var(--font-size-nav);
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: var(--color-text-subtle);
  transition: color var(--transition-medium);
}

.nav-link--active {
  color: var(--color-text-main);
}

.nav-link::after {
  content: '';
  position: absolute;
  left: 0;
  bottom: -6px;
  width: 0;
  height: 1px;
  background-color: var(--color-accent);
  transition: width var(--transition-fast);
}

.nav-link:hover {
  color: var(--color-text-soft);
}

.nav-link:hover::after {
  width: 100%;
}

/* Main */

.site-main {
  min-height: 40vh;
  padding-bottom: var(--space-7);
}

/* Footer */

.site-footer {
  border-top: 1px solid var(--color-border-subtle);
  padding-block: var(--space-6);
  background-color: var(--color-bg-primary);
}

.footer-inner {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-5);
  align-items: flex-start;
  justify-content: space-between;
}

.footer-brand {
  max-width: 280px;
}

.footer-logo {
  display: inline-block;
  margin-bottom: var(--space-2);
  font-family: var(--font-heading);
  font-weight: 500;
  font-size: 16px;
  letter-spacing: 0.26em;
  text-transform: uppercase;
  color: var(--color-text-main);
}

.footer-tagline {
  margin: 0;
  font-size: var(--font-size-sm);
  color: var(--color-text-muted);
  line-height: var(--line-height-relaxed);
}

.footer-nav {
  flex: 1 1 480px;
}

.footer-columns {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
  gap: var(--space-4) var(--space-6);
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
}

.footer-item + .footer-item {
  margin-top: var(--space-2);
}

.footer-link {
  display: inline-block;
  font-size: var(--font-size-sm);
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--color-text-subtle);
  transition: color var(--transition-medium);
}

.footer-link:hover {
  color: var(--color-text-soft);
}

.footer-meta {
  margin-top: var(--space-5);
  padding-top: var(--space-3);
  border-top: 1px solid var(--color-border-subtle);
  font-size: var(--font-size-xs);
  color: var(--color-text-subtle);
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: var(--space-3);
}

/* Responsiveness */

@media (max-width: 960px) {
  .site-header {
    padding-bottom: var(--space-4);
  }

  .nav-pill {
    padding-inline: 20px;
  }

  .nav-list {
    gap: 12px;
  }

  .nav-link {
    letter-spacing: 0.18em;
  }

  .footer-inner {
    flex-direction: column;
  }

  .footer-meta {
    flex-direction: column;
    align-items: flex-start;
  }
}

@media (max-width: 640px) {
  .shell {
    padding-inline: var(--space-3);
  }

  .nav-pill {
    padding-block: 12px;
    padding-inline: 16px;
  }

  .logo-text {
    font-size: 18px;
    letter-spacing: 0.16em;
  }

  .nav-list {
    justify-content: flex-start;
  }

  .nav-link {
    font-size: 10px;
  }

  .site-footer {
    padding-block: var(--space-5);
  }
}
